import axios from "axios";
const url = "http://localhost:8080/api/robotApi";

// פונקציה להמרת שם התמונה לכתובת URL מלאה
export const getImageUrl = (img) => {
    if (!img || img === "undefined") return ""; 
    
    // ניקוי מירכאות אם נכנסו בטעות מה-DB
    let cleanImg = img.toString().replace(/['"]+/g, '').trim();

    // אם זו תמונה ישנה מהאינטרנט (מתחילה ב-http)
    if (cleanImg.startsWith('http')) return cleanImg;
    
    // עבור תמונות חדשות מהשרת (תיקיית image)
    // encodeURIComponent מטפל בשמות עם עברית או רווחים
    return `http://localhost:8080/image/${encodeURIComponent(cleanImg)}`;
};

// חיפוש כל הרובוטים
export const getAll = async () => {
    try {
        const { data } = await axios.get(`${url}/getAllRobots`);
        return data;
    } catch (e) {
        console.error("שגיאה בשליפת רובוטים:", e);
    }
};

// חיפוש רובוט לפי קוד
export const getById = async (id) => {
    try {
        const { data } = await axios.get(`${url}/getRobotById/${id}`);
        return data;
    } catch (e) {
        console.error("שגיאה בשליפת רובוט:", e);
    }
};

// הוספת רובוט
export const addRobot = async (robot) => {
    try {
        // שימי לב: בהוספה אנחנו שולחים את ה-FormData
        const { data } = await axios.post(`${url}/postRobot`, robot);
        return data;
    } catch (e) {
        console.error("שגיאה בהוספת רובוט:", e);
    }
};
